{% extends "base.html" %}
{% block title %}Decision recorded -- Catalyst Integrity Desk{% endblock %}
{% block content %}

<h1>Decision recorded</h1>

{# ------------------------------------------------------------------
   Decision receipt: who decided, what changed, the timestamp,
   the previous ledger hash, the new ledger hash, thesis state.
   Hashes come from ledger entries -- the chain is the proof.
   ------------------------------------------------------------------ #}
<div style="background:#161b22; border:1px solid #30363d; border-radius:6px;
            padding:20px; max-width:720px; margin-bottom:24px;">

  {# Verdict + integrity badge side by side #}
  <div style="display:flex; align-items:center; justify-content:space-between;
              margin-bottom:20px;">
    <div>
      <span style="font-size:11px; color:#8b949e; text-transform:uppercase;
                   letter-spacing:0.07em;">Verdict</span>
      <div style="margin-top:4px;">
        {% if verdict == "approve" %}
          <span style="color:#10b981; font-weight:bold; font-size:15px;">Accepted</span>
        {% else %}
          <span style="color:#f85149; font-weight:bold; font-size:15px;">Rejected</span>
        {% endif %}
      </div>
    </div>
    {# Ledger integrity badge -- calls verify() at render time #}
    <div>
      <span style="font-size:11px; color:#8b949e; text-transform:uppercase;
                   letter-spacing:0.07em;">Ledger integrity</span>
      <div style="margin-top:4px;">
        {% if intact %}
          <span style="background:#1a4731; color:#10b981; border:1px solid #10b981;
                       font-size:12px; padding:4px 14px; border-radius:3px; font-weight:bold;">
            &#10003; intact
          </span>
        {% else %}
          <span style="background:#3d1414; color:#f85149; border:1px solid #f85149;
                       font-size:12px; padding:4px 14px; border-radius:3px; font-weight:bold;">
            &#10007; tampered
          </span>
        {% endif %}
      </div>
    </div>
  </div>

  <hr>

  {# Receipt detail #}
  {% if receipt %}
  <div style="margin:16px 0;">
    <div style="font-size:11px; color:#8b949e; text-transform:uppercase;
                letter-spacing:0.07em; margin-bottom:10px;">Receipt</div>
    <table style="max-width:680px; font-size:12px;">
      <tbody>
        <tr>
          <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Author</td>
          <td>{{ receipt.author }}</td>
        </tr>
        <tr>
          <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Timestamp</td>
          <td>{{ receipt.ts_display }}</td>
        </tr>
        <tr>
          <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Card</td>
          <td><span class="tag">{{ receipt.card_id }}</span></td>
        </tr>
        <tr>
          <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">What changed</td>
          <td>{{ receipt.what_changed }}</td>
        </tr>
        <tr>
          <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Thesis state</td>
          <td>
            {% if receipt.thesis_state == "financing required before catalyst" %}
              <span class="verdict-alert">{{ receipt.thesis_state }}</span>
            {% elif receipt.thesis_state == "funded to catalyst" %}
              <span class="verdict-ok">{{ receipt.thesis_state }}</span>
            {% else %}
              {{ receipt.thesis_state }}
            {% endif %}
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  {# Hash chain: the most impressive thing in the system, made visible #}
  <hr>
  <div style="margin-top:16px;">
    <div style="font-size:11px; color:#8b949e; text-transform:uppercase;
                letter-spacing:0.07em; margin-bottom:12px;">Hash chain</div>

    {# Chain diagram: observation -> Granite memo -> human decision -> hash verified #}
    <div style="display:flex; align-items:center; gap:6px; flex-wrap:wrap;
                margin-bottom:16px; font-size:11px;">
      <span style="background:#0d1117; border:1px solid #30363d; border-radius:3px;
                   padding:4px 10px; color:#c9d1d9;">observation</span>
      <span style="color:#30363d;">&#8594;</span>
      <span style="background:#0d1117; border:1px solid #1e3a5f; border-radius:3px;
                   padding:4px 10px; color:#60a5fa;">Granite memo</span>
      <span style="color:#30363d;">&#8594;</span>
      <span style="background:#0d1117; border:1px solid #30363d; border-radius:3px;
                   padding:4px 10px; color:#c9d1d9;">human decision</span>
      <span style="color:#30363d;">&#8594;</span>
      {% if intact %}
        <span style="background:#1a4731; border:1px solid #10b981; border-radius:3px;
                     padding:4px 10px; color:#10b981; font-weight:bold;">hash verified</span>
      {% else %}
        <span style="background:#3d1414; border:1px solid #f85149; border-radius:3px;
                     padding:4px 10px; color:#f85149; font-weight:bold;">hash FAILED</span>
      {% endif %}
    </div>

    <table style="max-width:680px; font-size:11px;">
      <tbody>
        <tr>
          <td style="color:#8b949e; padding:4px 12px 4px 0; white-space:nowrap;">Prev hash</td>
          <td style="font-family:ui-monospace,monospace; color:#6b7280;
                     word-break:break-all;">{{ receipt.prev_hash }}</td>
        </tr>
        <tr>
          <td style="color:#8b949e; padding:4px 12px 4px 0; white-space:nowrap;">Entry hash</td>
          <td style="font-family:ui-monospace,monospace; color:#10b981;
                     word-break:break-all;">{{ receipt.entry_hash }}</td>
        </tr>
      </tbody>
    </table>
  </div>
  {% endif %}

</div>

<blockquote style="border-left:3px solid #30363d; padding-left:12px;
                   color:#8b949e; font-size:11px; line-height:1.6;
                   max-width:720px; margin-bottom:16px;">
  Tamper demo: edit one byte of <code>data/decisions.jsonl</code>, then reload
  this page to see <code>verify()</code> return false and the hash chain break.
</blockquote>

<p style="font-size:12px;">
  <a href="/redline">&larr; Back to redline</a>
  &nbsp;|&nbsp;
  <a href="/contracts">Contract list</a>
</p>

{% endblock %}

